// Memory Consolidation — summarize daily interactions into long-term memory with vector embeddings,
// then extract user insights (behavioral patterns, stressors, preferences) for active user modeling.
//
// Flow:
// 1. Load cursor (last processed memory_daily ID) from heartbeat_config
// 2. Load all memory_daily entries since cursor
// 3. Skip if no new entries
// 4. Summarize with LLM (provider from tools_config)
// 5. Generate embedding via configurable provider
// 6. Save summary + embedding to memory_long (category='consolidated')
// 7. Update cursor
// 8. NEW: Extract user insights from this run's summaries + existing insights (7d window)
//    -> save as category='insight' (importance 8-9, no expires_at, source='consolidation-pattern')
//    -> mark contradicted prior insights via metadata.outdated=true
// 9. Clean up old reminders (delivered > 30 days ago)
// 10. Clean up expired memories (expires_at < now)

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const http = this.helpers.httpRequest;

// --- Helper: PostgREST request ---
async function pgrest(method, path, body, extraHeaders = {}) {
  const opts = {
    method,
    url: `${SUPABASE_URL}${path}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Content-Type': 'application/json',
      ...extraHeaders
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };
  if (body) opts.body = body;
  const res = await http(opts);
  return res.body;
}

// --- Helper: Generate embedding via configurable provider (config from DB) ---
async function getEmbedding(text) {
  const cfgResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.embedding&select=config,enabled');
  const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0 && cfgResp[0].enabled) ? cfgResp[0].config : null;
  if (!cfg || !cfg.api_key) return null;
  const provider = cfg.provider || 'openai';
  const apiKey = cfg.api_key;
  const model = cfg.model || 'text-embedding-3-small';

  try {
    if (provider === 'openai') {
      const data = await http({
        method: 'POST',
        url: 'https://api.openai.com/v1/embeddings',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: { model, input: text }
      });
      return data.data[0].embedding;
    }
    if (provider === 'voyage') {
      const data = await http({
        method: 'POST',
        url: 'https://api.voyageai.com/v1/embeddings',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: { model: model || 'voyage-3-lite', input: [text] }
      });
      return data.data[0].embedding;
    }
    if (provider === 'ollama') {
      const ollamaUrl = cfg.ollama_url || 'http://localhost:11434';
      const data = await http({
        method: 'POST',
        url: `${ollamaUrl}/api/embed`,
        headers: { 'Content-Type': 'application/json' },
        body: { model: model || 'nomic-embed-text', input: text }
      });
      return data.embeddings[0];
    }
  } catch (e) {
    return null;
  }
  return null;
}

// --- Helper: Generic LLM call (provider-agnostic, config from DB). Used by summarize + insight extraction. ---
async function callLLM(systemPrompt, userText, maxTokens = 1024) {
  // 1. Try llm_provider config (new installs)
  const llmResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.llm_provider&select=config,enabled');
  let cfg = (Array.isArray(llmResp) && llmResp.length > 0 && llmResp[0].enabled) ? llmResp[0].config : null;

  // 2. Fallback to legacy 'anthropic' config (existing installs)
  if (!cfg) {
    const legacyResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.anthropic&select=config');
    const legacyKey = (Array.isArray(legacyResp) && legacyResp.length > 0) ? legacyResp[0].config.api_key : null;
    if (legacyKey) {
      cfg = { provider: 'anthropic', endpoint: 'https://api.anthropic.com/v1/messages', model: 'claude-haiku-4-5-20251001', api_key: legacyKey };
    }
  }

  if (!cfg || !cfg.api_key) throw new Error('No LLM provider configured in tools_config (set llm_provider or anthropic)');

  // 3. Provider dispatch
  if (cfg.provider === 'anthropic') {
    const data = await http({
      method: 'POST',
      url: cfg.endpoint || 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': cfg.api_key, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: cfg.model || 'claude-haiku-4-5-20251001', max_tokens: maxTokens, system: systemPrompt, messages: [{ role: 'user', content: userText }] }
    });
    if (data.error) throw new Error(`LLM API error: ${data.error.message}`);
    return data.content[0].text;
  } else {
    const headers = { 'Content-Type': 'application/json' };
    if (cfg.api_key && cfg.api_key !== 'not-needed' && cfg.api_key !== 'ollama') {
      headers['Authorization'] = `Bearer ${cfg.api_key}`;
    }
    const data = await http({
      method: 'POST',
      url: cfg.endpoint,
      headers,
      body: { model: cfg.model, max_tokens: maxTokens, messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userText }] }
    });
    if (data.error) throw new Error(`LLM API error: ${JSON.stringify(data.error)}`);
    return data.choices[0].message.content;
  }
}

const SUMMARIZE_PROMPT = 'Summarize the following conversation log into key facts, decisions, preferences, and context worth remembering long-term. Be concise and structured. Output plain text, no markdown headers.';

async function summarize(text) {
  return callLLM(SUMMARIZE_PROMPT, text, 1024);
}

// === Main Logic ===

// 1. Load cursor
let cursor = 0;
try {
  const cursorData = await pgrest('GET', '/rest/v1/heartbeat_config?check_name=eq.memory_consolidation&select=config');
  if (Array.isArray(cursorData) && cursorData.length > 0 && cursorData[0].config && cursorData[0].config.last_id) {
    cursor = cursorData[0].config.last_id;
  }
} catch (e) {
  // No cursor yet — start from 0
}

// 2. Load new memory_daily entries
const entries = await pgrest('GET', `/rest/v1/memory_daily?id=gt.${cursor}&order=id.asc`);
if (!Array.isArray(entries) || entries.length === 0) {
  return [{ json: { status: 'no_new_entries', cursor } }];
}

// 3. Group entries by date
const byDate = {};
for (const entry of entries) {
  const d = entry.date || 'unknown';
  if (!byDate[d]) byDate[d] = [];
  byDate[d].push(entry);
}

// 4. Process each date group
const results = [];
let maxId = cursor;

for (const [date, dayEntries] of Object.entries(byDate)) {
  const text = dayEntries.map(e => `[${e.role}] ${e.content}`).join('\n');

  // Skip very short entries (less than 50 chars total)
  if (text.length < 50) {
    const dayMaxId = Math.max(...dayEntries.map(e => e.id));
    if (dayMaxId > maxId) maxId = dayMaxId;
    results.push({ date, entries: dayEntries.length, skipped: true, reason: 'too_short' });
    continue;
  }

  // Summarize with LLM
  const summary = await summarize(text);

  // Extract tags and entity names from summary
  let meta = { tags: [], entities: [] };
  try {
    const metaPrompt = 'Extract from this text: 1) tags: 2-5 keyword strings, 2) entities: person/company/place/event names mentioned. Return JSON only: {"tags":[],"entities":[]}';
    const metaRaw = await callLLM(metaPrompt, summary, 512);
    const cleaned = metaRaw.replace(/```json\n?|\n?```/g, '').trim();
    meta = JSON.parse(cleaned);
  } catch (e) { /* non-critical — proceed without metadata */ }

  // Generate embedding
  const embedding = await getEmbedding(summary);

  // Save to memory_long
  const saveBody = {
    content: summary,
    category: 'consolidated',
    importance: 7,
    metadata: { source: 'consolidation', date, entry_count: dayEntries.length },
    source: 'consolidation'
  };
  if (meta.tags && meta.tags.length > 0) saveBody.tags = meta.tags;
  if (meta.entities && meta.entities.length > 0) saveBody.entity_name = meta.entities[0];
  if (embedding) saveBody.embedding = JSON.stringify(embedding);
  // Auto-expiry: consolidated memories expire after 90 days
  saveBody.expires_at = new Date(Date.now() + 90 * 24 * 60 * 60 * 1000).toISOString();

  await pgrest('POST', '/rest/v1/memory_long', saveBody, { 'Prefer': 'return=minimal' });

  const dayMaxId = Math.max(...dayEntries.map(e => e.id));
  if (dayMaxId > maxId) maxId = dayMaxId;

  results.push({ date, entries: dayEntries.length, summarized: true, vectorized: !!embedding, summary });
}

// 5. Update cursor
await pgrest('PATCH', '/rest/v1/heartbeat_config?check_name=eq.memory_consolidation', {
  config: { last_id: maxId, last_run: new Date().toISOString() }
});

// 5b. NEW: Extract user insights (behavioral patterns) from this run's summaries.
// Compares against existing insights from last 7 days. Marks contradicted ones as outdated.
const summariesText = results.filter(r => r.summarized && r.summary).map(r => `[${r.date}] ${r.summary}`).join('\n\n---\n\n');
let insightsExtracted = 0;
let insightError = null;

if (summariesText.length > 0) {
  try {
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
    const recentInsights = await pgrest('GET', `/rest/v1/memory_long?category=eq.insight&created_at=gt.${sevenDaysAgo}&select=id,content,importance,created_at&order=importance.desc,created_at.desc&limit=20`);
    const existingBlock = (Array.isArray(recentInsights) && recentInsights.length > 0)
      ? recentInsights.map(i => `[id ${i.id}] (importance ${i.importance}) ${i.content}`).join('\n')
      : '(none)';

    const insightSystemPrompt = 'You analyze user behavior to extract durable insights about the user — patterns, stressors, communication style, work rhythm, preferences. Output ONLY valid JSON: an array of objects {content, importance, tags, status, refers_to_id?}. Rules: content = ONE sentence describing a behavioral pattern (NOT a fact restatement). importance = integer 8 or 9 (9 only for strongly evidenced patterns). tags = array of short keyword strings. status = "new" (no prior insight matches), "reinforced" (matches an existing insight — set refers_to_id), or "contradicted" (existing insight is contradicted — set refers_to_id). Return 0-5 insights. Quality > quantity. Bad: "user mentioned X today". Good: "user works in short intensive bursts, rarely long planning phases". If no clear pattern, return [].';
    const insightUserText = `Recent consolidations:\n${summariesText}\n\nExisting insights (last 7 days):\n${existingBlock}`;

    const rawInsights = await callLLM(insightSystemPrompt, insightUserText, 2048);
    const cleanedInsights = rawInsights.replace(/```json\n?|\n?```/g, '').trim();
    const insights = JSON.parse(cleanedInsights);

    if (Array.isArray(insights)) {
      for (const ins of insights) {
        if (!ins || typeof ins.content !== 'string' || ins.content.length < 10) continue;

        // contradicted -> mark prior insight as outdated
        if (ins.status === 'contradicted' && ins.refers_to_id) {
          try {
            await pgrest('PATCH', `/rest/v1/memory_long?id=eq.${ins.refers_to_id}`, {
              metadata: { outdated: true, outdated_at: new Date().toISOString(), outdated_by_run: maxId }
            });
          } catch (e) { /* non-critical */ }
        }

        const importance = (typeof ins.importance === 'number' && ins.importance >= 8 && ins.importance <= 9) ? ins.importance : 8;
        const userTags = Array.isArray(ins.tags) ? ins.tags.filter(t => typeof t === 'string') : [];
        const allTags = ['insight', 'pattern', 'user-modeling', ins.status || 'new', ...userTags];

        const insightEmbedding = await getEmbedding(ins.content);
        const insightBody = {
          content: ins.content,
          category: 'insight',
          importance,
          tags: allTags,
          source: 'consolidation-pattern',
          metadata: { status: ins.status || 'new', refers_to_id: ins.refers_to_id || null }
        };
        if (insightEmbedding) insightBody.embedding = JSON.stringify(insightEmbedding);
        // No expires_at — insights persist; relevance decays via importance-weighted half-life in hybrid_search

        await pgrest('POST', '/rest/v1/memory_long', insightBody, { 'Prefer': 'return=minimal' });
        insightsExtracted++;
      }
    }
  } catch (e) {
    insightError = String(e.message || e).slice(0, 200);
  }
}

// 6. Clean up old reminders (delivered more than 30 days ago)
const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
await pgrest('DELETE', `/rest/v1/reminders?reminded_at=not.is.null&reminded_at=lt.${cutoff}`);

// 7. Clean up expired memories
await pgrest('DELETE', '/rest/v1/memory_long?expires_at=not.is.null&expires_at=lt.' + new Date().toISOString());

// Strip summary from results to avoid leaking long text into status output
const resultsClean = results.map(r => { const { summary, ...rest } = r; return rest; });

return [{ json: { status: 'completed', processed: resultsClean, new_cursor: maxId, insights_extracted: insightsExtracted, insight_error: insightError } }];
